#include <bits/stdc++.h>
using namespace std;
typedef long long ll;

int n;
ll a[500005];

ll m(ll l, ll r) {
    if (abs(r - l) > 5) {
        ll tmp = ll((l + r) / 2LL);
        // ll ans=((m(l, tmp) % max(m(tmp + 1, r), ll(7))) + (a[tmp] - 1));
        // cout<<tmp<<endl;
        return ((m(l, tmp) % max(m(tmp + 1, r), 7LL) + (a[tmp] - 1)));
    }
    else if (abs(r - l) <= 5) {
        ll maxn = INT_MIN;
        for (ll i = l; i <= r; i++) {
            maxn = max(maxn, a[i]);
        }
        // cout<<maxn<<"*"<<endl;
        return maxn;
    }
}

int main() {
    cin >> n;
    for (int i = 1; i <= n; i++) {
        cin >> a[i];
    }
    cout << m(1, n);
    return 0;
}
